// pyutil.test.ts — verify pyRound matches CPython round() byte-for-byte against
// a 517-case battery generated by python3 round() (pyround-battery.json), plus
// the formatters used by gate.py / sparkline.py.
import { expect, test } from "bun:test";
import { readFileSync } from "node:fs";
import { join } from "node:path";
import { pyRound, pyFixed, pySignedFixed, pyPercent, pySplitlines } from "./pyutil.ts";

const battery: Array<[number, number, number, number, number]> = JSON.parse(
  readFileSync(join(import.meta.dir, "pyround-battery.json"), "utf-8"),
);

test("pyRound matches CPython round() across the 517-case battery (ndigits 4,2,1,0)", () => {
  let checked = 0;
  for (const [x, r4, r2, r1, r0] of battery) {
    expect(pyRound(x, 4)).toBe(r4);
    expect(pyRound(x, 2)).toBe(r2);
    expect(pyRound(x, 1)).toBe(r1);
    expect(pyRound(x, 0)).toBe(r0);
    checked++;
  }
  expect(checked).toBe(battery.length);
});

test("pyRound: the round-half-up-divergence cases Python decides via TRUE value", () => {
  // round(0.12345,4): stored double is just ABOVE 0.12345 → 0.1235 (NOT a tie)
  expect(pyRound(0.12345, 4)).toBe(0.1235);
  // round(2.675,2): stored double is 2.6749999… → 2.67 (NOT 2.68)
  expect(pyRound(2.675, 2)).toBe(2.67);
  // exact decimal ties → half-to-even
  expect(pyRound(0.125, 2)).toBe(0.12); // 2 is even
  expect(pyRound(0.375, 2)).toBe(0.38); // 4 is even
  expect(pyRound(0.5, 0)).toBe(0);
  expect(pyRound(1.5, 0)).toBe(2);
  expect(pyRound(2.5, 0)).toBe(2);
  expect(pyRound(3.5, 0)).toBe(4);
});

test("pyRound: identity / zero / negative-zero", () => {
  expect(pyRound(1.0, 4)).toBe(1.0);
  expect(pyRound(0.7702, 4)).toBe(0.7702);
  expect(pyRound(0, 4)).toBe(0);
  expect(Object.is(pyRound(-0, 4), -0)).toBe(true);
});

test("pySplitlines matches CPython str.splitlines() boundary set + no trailing empty", () => {
  // Counts verified against python3 [len(s.splitlines()) for s in ...].
  expect(pySplitlines("a\n")).toEqual(["a"]); // trailing break → no phantom empty
  expect(pySplitlines("a\nb")).toEqual(["a", "b"]);
  expect(pySplitlines("")).toEqual([]);
  expect(pySplitlines("a\x0cb").length).toBe(2); // form-feed is a boundary
  expect(pySplitlines("x\r\ny").length).toBe(2); // CRLF is ONE boundary
  expect(pySplitlines("q\rr").length).toBe(2); // bare CR
  expect(pySplitlines("a b c")).toEqual(["a b c"]); // spaces are NOT boundaries
  expect(pySplitlines("v\x0bt").length).toBe(2); // vertical tab
  expect(pySplitlines("n\x85e").length).toBe(2); // NEL
});

test("pyFixed / pySignedFixed / pyPercent — Python format-spec parity", () => {
  // gate.py:77 "{:+.3f}"
  expect(pySignedFixed(0.05, 3)).toBe("+0.050");
  expect(pySignedFixed(-0.025, 3)).toBe("-0.025");
  // gate.py:76 "{:.3f}"
  expect(pyFixed(0.891, 3)).toBe("0.891");
  expect(pyFixed(0.8905, 3)).toBe("0.890"); // half-to-even: 0 is even
  // gate.py:64 "{:.1%}"
  expect(pyPercent(1.0, 1)).toBe("100.0%");
  expect(pyPercent(0.9667, 1)).toBe("96.7%");
});
